import { useState } from "react";
import { loginUser } from "../services/auth";
import { FaUser, FaLock, FaEye, FaEyeSlash, FaBuilding } from "react-icons/fa";
import { motion } from "framer-motion";
import "./Login.css";

function Login() {

    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);

    const handleLogin = async (e) => {

        e.preventDefault();

        try {

            const response = await loginUser(
                username,
                password
            );

            localStorage.setItem(
                "token",
                response.data.access_token
            );

            window.location.href = "/dashboard";

        }
        catch (error) {

            alert(
                error.response?.data?.detail ||
                error.message
            );

        }

    };

    return (

        <div className="login-container">

            <div className="left-panel">

                <FaBuilding className="logo-icon" />

                <h1>Rental Management System</h1>

                <p>
                    Manage Properties, Tenants, Payments and Blockchain
                    Verification in one modern platform.
                </p>

                <div className="feature-list">

                    <div>✔ Property Management</div>
                    <div>✔ Tenant Records</div>
                    <div>✔ Payment Tracking</div>
                    <div>✔ Blockchain Verification</div>
                    <div>✔ Analytics Dashboard</div>

                </div>

            </div>

            <motion.div
                className="right-panel"
                initial={{ opacity: 0, x: 50 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.7 }}
            >

                <div className="login-card">

                    <h2>Welcome Back 👋</h2>

                    <p>Sign in to continue</p>

                    <form onSubmit={handleLogin}>

                        <div className="input-box">

                            <FaUser className="icon" />

                            <input
                                placeholder="Username"
                                value={username}
                                onChange={(e) =>
                                    setUsername(e.target.value)
                                }
                            />

                        </div>

                        <div className="input-box">

                            <FaLock className="icon" />

                            <input
                                type={
                                    showPassword ?
                                        "text" :
                                        "password"
                                }
                                placeholder="Password"
                                value={password}
                                onChange={(e) =>
                                    setPassword(e.target.value)
                                }
                            />

                            <div
                                className="eye-icon"
                                onClick={() =>
                                    setShowPassword(!showPassword)
                                }
                            >

                                {
                                    showPassword ?
                                        <FaEyeSlash /> :
                                        <FaEye />
                                }

                            </div>

                        </div>

                        <button className="login-btn">

                            Login

                        </button>

                    </form>

                </div>

            </motion.div>

        </div>

    );

}

export default Login;
